SET NOCOUNT ON;

DECLARE @DBName NVARCHAR(128);
DECLARE @SQL NVARCHAR(MAX);

-- Tabla temporal para almacenar resultados
IF OBJECT_ID('tempdb..#DBSpaceInfo') IS NOT NULL DROP TABLE #DBSpaceInfo;
CREATE TABLE #DBSpaceInfo (
    DatabaseName SYSNAME,
    TableName SYSNAME,
    TotalSpaceGB DECIMAL(18,2)
);

-- Tabla para registrar errores
IF OBJECT_ID('tempdb..#ErroresDB') IS NOT NULL DROP TABLE #ErroresDB;
CREATE TABLE #ErroresDB (
    DatabaseName SYSNAME,
    ErrorMessage NVARCHAR(MAX),
    ErrorTime DATETIME DEFAULT GETDATE()
);

-- Cursor con bases a las que tienes acceso
DECLARE db_cursor CURSOR FOR
SELECT name 
FROM sys.databases 
WHERE state_desc = 'ONLINE' 
    AND name NOT IN ('master', 'tempdb', 'model', 'msdb')
    AND HAS_DBACCESS(name) = 1;

OPEN db_cursor;
FETCH NEXT FROM db_cursor INTO @DBName;

WHILE @@FETCH_STATUS = 0
BEGIN
    SET @SQL = N'
    BEGIN TRY
        USE ' + QUOTENAME(@DBName) + N';

        INSERT INTO #DBSpaceInfo (DatabaseName, TableName, TotalSpaceGB)
        SELECT 
            N''' + @DBName + N''' AS DatabaseName,
            t.name AS TableName,
            CAST(SUM(a.total_pages) * 8.0 / 1024 / 1024 AS DECIMAL(18,2)) AS TotalSpaceGB
        FROM 
            sys.tables t
        INNER JOIN 
            sys.indexes i ON t.object_id = i.object_id
        INNER JOIN 
            sys.partitions p ON i.object_id = p.object_id AND i.index_id = p.index_id
        INNER JOIN 
            sys.allocation_units a ON p.partition_id = a.container_id
        INNER JOIN 
            sys.schemas s ON t.schema_id = s.schema_id
        WHERE 
            i.index_id <= 1 AND p.rows > 0
        GROUP BY 
            s.name, t.name;
    END TRY
    BEGIN CATCH
        INSERT INTO #ErroresDB (DatabaseName, ErrorMessage)
        VALUES (N''' + @DBName + N''', ERROR_MESSAGE());
    END CATCH;
    ';

    EXEC sp_executesql @SQL;

    FETCH NEXT FROM db_cursor INTO @DBName;
END

CLOSE db_cursor;
DEALLOCATE db_cursor;

-- Resultados: Espacio por tabla
SELECT TOP 10 
    DatabaseName AS 'Base de Datos',
    TableName AS 'Tabla',
    TotalSpaceGB AS 'Espacio GB'
FROM #DBSpaceInfo
ORDER BY TotalSpaceGB DESC;

-- (Opcional) Ver errores si los hubo
-- SELECT * FROM #ErroresDB;

-- Limpiar tablas temporales
DROP TABLE IF EXISTS #DBSpaceInfo;
DROP TABLE IF EXISTS #ErroresDB;

